<template>
  <section v-if="selectedProject" class="portal-module project-manager">
    <ProjectBoardManager :project="selectedProject" :admin="admin" @back="selectedProject = null" />
  </section>
  <section v-else class="portal-module project-manager">
    <div class="portal-module__head">
      <div><span class="portal-module__eyebrow">Projetos</span><h2>{{ admin ? 'Operacoes em um so lugar' : 'Seus projetos' }}</h2><p>{{ admin ? 'Acompanhe entregas, documentos, financeiro e board por cliente.' : 'Acompanhe o andamento e os documentos de cada projeto.' }}</p></div>
      <q-btn v-if="admin" unelevated no-caps class="portal-module__primary" icon="mdi-plus" label="Novo projeto" @click="openCreate" />
    </div>
    <div class="project-manager__filters"><q-input v-if="admin" v-model="search" outlined dense clearable label="Buscar projeto" @keyup.enter="load"><template #prepend><q-icon name="mdi-magnify" /></template></q-input><q-btn flat round icon="mdi-refresh" aria-label="Atualizar projetos" :loading="loading" @click="load"><q-tooltip>Atualizar</q-tooltip></q-btn></div>
    <div v-if="!loading && !projects.length" class="project-manager__empty"><q-icon name="mdi-folder-open-outline" size="38px" /><strong>Nenhum projeto encontrado</strong><span>Os projetos vinculados ao cliente aparecerão aqui.</span></div>
    <div class="project-manager__grid">
      <article v-for="project in projects" :key="project._id" class="project-card">
        <div class="project-card__logo"><img v-if="project.logo" :src="project.logo.url" :alt="project.title" /><q-icon v-else name="mdi-folder-star-outline" size="34px" /></div>
        <div class="project-card__body"><div class="project-card__top"><span class="project-card__status">{{ statusLabel(project.status) }}</span><span v-if="admin">{{ project.client?.name || 'Projeto interno' }}</span></div><h3>{{ project.title }}</h3><p>{{ preview(project.description) }}</p><div class="project-card__links"><a v-if="project.githubLink" :href="project.githubLink" target="_blank" rel="noopener noreferrer"><q-icon name="mdi-github" /> GitHub</a><a v-for="link in project.links || []" :key="`${project._id}-${link.link}`" :href="link.link" target="_blank" rel="noopener noreferrer"><q-icon name="mdi-open-in-new" /> {{ link.title }}</a></div></div>
        <div class="project-card__footer"><div class="project-card__stats"><span><q-icon name="mdi-view-kanban-outline" /> {{ project.counts?.tasks || 0 }} tarefas</span><span><q-icon name="mdi-file-document-outline" /> {{ project.counts?.contracts || 0 }} docs</span><span><q-icon name="mdi-cash-multiple" /> {{ project.counts?.costs || 0 }} custos</span></div><div class="project-card__actions"><q-btn flat dense no-caps icon="mdi-view-dashboard-outline" label="Abrir board" @click="selectedProject = project" /><q-btn v-if="admin" flat round dense icon="mdi-pencil" aria-label="Editar projeto" @click="openEdit(project)" /><q-btn v-if="admin" flat round dense color="negative" icon="mdi-delete-outline" aria-label="Excluir projeto" @click="remove(project)" /></div></div>
      </article>
    </div>

    <q-dialog v-model="dialog"><q-card class="portal-module__dialog project-manager__dialog"><q-card-section class="portal-module__dialog-head"><div><span class="portal-module__eyebrow">Workspace</span><h3>{{ form._id ? 'Editar projeto' : 'Cadastrar projeto' }}</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="dialog = false" /></q-card-section><q-card-section><q-form @submit.prevent="save"><q-input v-model="form.title" outlined label="Titulo" :rules="[requiredRule]" /><q-select v-model="form.clientId" outlined label="Cliente" :options="customerOptions" emit-value map-options clearable class="q-mt-sm" /><q-select v-model="form.status" outlined label="Status" :options="statusOptions" emit-value map-options class="q-mt-sm" /><q-input v-model="form.githubLink" outlined label="Link do GitHub" class="q-mt-sm"><template #prepend><q-icon name="mdi-github" /></template></q-input><q-input v-model="form.description" outlined type="textarea" autogrow label="Descricao" class="q-mt-sm" /><div class="project-manager__link-head"><span>Links do projeto</span><q-btn flat round dense icon="mdi-plus" aria-label="Adicionar link" @click="form.links.push({ title: '', link: '' })" /></div><div v-for="(link, index) in form.links" :key="index" class="project-manager__link-row"><q-input v-model="link.title" outlined dense label="Titulo do link" /><q-input v-model="link.link" outlined dense label="URL" /><q-btn flat round dense color="negative" icon="mdi-close" aria-label="Remover link" @click="form.links.splice(index, 1)" /></div><q-file v-model="form.file" outlined label="Logo do projeto" accept="image/*" class="q-mt-sm"><template #prepend><q-icon name="mdi-image-plus-outline" /></template></q-file><q-toggle v-if="form._id && form.logo" v-model="form.removeLogo" label="Remover logo atual" color="negative" class="q-mt-sm" /><q-btn unelevated no-caps class="portal-module__primary full-width q-mt-md" type="submit" label="Salvar projeto" :loading="saving" /></q-form></q-card-section></q-card></q-dialog>
  </section>
</template>

<script setup>
import { computed, onMounted, ref } from 'vue'
import { useQuasar } from 'quasar'
import { api } from 'boot/axios'
import ProjectBoardManager from 'components/ProjectBoardManager.vue'

const props = defineProps({ admin: { type: Boolean, default: false } })
const $q = useQuasar()
const token = localStorage.getItem(props.admin ? 'aito_admin_token' : 'aito_user_token')
const headers = { Authorization: `Bearer ${token}` }
const projects = ref([]); const customers = ref([]); const selectedProject = ref(null); const loading = ref(false); const saving = ref(false); const dialog = ref(false); const search = ref(''); const form = ref(emptyForm())
const statusOptions = [{ label: 'Ativo', value: 'active' }, { label: 'Pausado', value: 'paused' }, { label: 'Concluido', value: 'completed' }, { label: 'Arquivado', value: 'archived' }]
const customerOptions = computed(() => customers.value.map((item) => ({ label: `${item.name} - ${item.email}`, value: item._id })))
function emptyForm () { return { _id: '', title: '', description: '', githubLink: '', status: 'active', clientId: '', links: [], file: null, logo: null, removeLogo: false } }
function requiredRule (value) { return Boolean(String(value || '').trim()) || 'Preencha este campo.' }
function preview (value) { const text = String(value || '').trim(); return text.length > 112 ? `${text.slice(0, 112)}...` : text || 'Sem descricao cadastrada.' }
function statusLabel (value) { return statusOptions.find((item) => item.value === value)?.label || value || '-' }
function selectedFile (value) { return value?.item ? value.item(0) : Array.isArray(value) ? value[0] : value }
function openCreate () { form.value = emptyForm(); dialog.value = true }
function openEdit (project) { form.value = { ...emptyForm(), ...project, clientId: project.client?.id || project.client?._id || '', links: (project.links || []).map((link) => ({ ...link })), file: null, removeLogo: false }; dialog.value = true }
async function load () { loading.value = true; try { const response = await api.get(props.admin ? '/admin/projects' : '/projects', { headers, params: props.admin ? { q: search.value } : undefined }); projects.value = response.data.data || []; if (props.admin) { const clients = await api.get('/admin/customers', { headers }); customers.value = clients.data.data || [] } } catch (error) { notifyError(error) } finally { loading.value = false } }
async function save () { saving.value = true; try { const body = new FormData(); body.append('title', form.value.title); body.append('description', form.value.description || ''); body.append('githubLink', form.value.githubLink || ''); body.append('status', form.value.status); body.append('clientId', form.value.clientId || ''); body.append('links', JSON.stringify(form.value.links || [])); if (form.value.removeLogo) body.append('removeLogo', 'true'); const file = selectedFile(form.value.file); if (file) body.append('attachment', file); const endpoint = form.value._id ? `/admin/projects/${form.value._id}` : '/admin/projects'; const response = form.value._id ? await api.put(endpoint, body, { headers }) : await api.post(endpoint, body, { headers }); if (form.value._id) projects.value = projects.value.map((item) => item._id === form.value._id ? response.data.data : item); else projects.value.unshift(response.data.data); dialog.value = false; $q.notify({ type: 'positive', message: 'Projeto salvo.' }) } catch (error) { notifyError(error) } finally { saving.value = false } }
function remove (project) { $q.dialog({ title: 'Excluir projeto', message: `Remover ${project.title}?`, cancel: true, persistent: true }).onOk(async () => { try { await api.delete(`/admin/projects/${project._id}`, { headers }); projects.value = projects.value.filter((item) => item._id !== project._id); $q.notify({ type: 'positive', message: 'Projeto removido.' }) } catch (error) { notifyError(error) } }) }
function notifyError (error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Nao foi possivel concluir o projeto.' }) }
onMounted(load)
</script>

<style scoped>
.portal-module { display: grid; gap: 1rem; color: #effffb; }.portal-module__head { display: flex; align-items: flex-end; justify-content: space-between; gap: 1rem; }.portal-module__eyebrow { color: #8fffee; font-size: .66rem; font-weight: 900; letter-spacing: .14em; text-transform: uppercase; }.portal-module h2 { margin: .45rem 0 0; color: #effffb; font-size: clamp(1.5rem, 3vw, 2.5rem); }.portal-module__head p { margin: .45rem 0 0; color: rgba(229,255,250,.62); font-size: .78rem; }.portal-module__primary { color: #03110f; background: linear-gradient(135deg, #8fffee, #13bc9d); font-weight: 800; }.project-manager__filters { display: flex; align-items: center; gap: .6rem; }.project-manager__filters :deep(.q-field) { width: min(100%, 420px); }.project-manager__filters :deep(.q-field__control), .project-manager__dialog :deep(.q-field__control) { color: #effffb; background: rgba(7,40,40,.74); }.project-manager__filters :deep(.q-field__native), .project-manager__filters :deep(.q-field__label), .project-manager__dialog :deep(.q-field__native), .project-manager__dialog :deep(.q-field__label) { color: rgba(239,255,251,.84); }.project-manager__grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: .8rem; }.project-card { display: grid; grid-template-columns: 72px 1fr; gap: .9rem; padding: 1rem; border: 1px solid rgba(19,188,157,.22); border-radius: .75rem; background: linear-gradient(135deg, rgba(7,35,35,.88), rgba(3,17,18,.76)); }.project-card__logo { display: grid; place-items: center; width: 72px; height: 72px; border-radius: .65rem; background: rgba(19,188,157,.13); color: #8fffee; overflow: hidden; }.project-card__logo img { width: 100%; height: 100%; object-fit: contain; }.project-card__body { min-width: 0; }.project-card__top, .project-card__footer { display: flex; align-items: center; justify-content: space-between; gap: .6rem; }.project-card__top { color: rgba(229,255,250,.58); font-size: .63rem; }.project-card__status { color: #8fffee; text-transform: uppercase; letter-spacing: .08em; }.project-card h3 { margin: .45rem 0 .25rem; font-size: 1rem; }.project-card p { margin: 0; color: rgba(239,255,251,.68); font-size: .75rem; line-height: 1.5; }.project-card__links { display: flex; flex-wrap: wrap; gap: .45rem; margin-top: .7rem; }.project-card__links a, .project-card__actions :deep(.q-btn) { color: #8fffee; text-decoration: none; font-size: .69rem; }.project-card__footer { grid-column: 1 / -1; padding-top: .8rem; border-top: 1px solid rgba(143,255,238,.1); }.project-card__stats { display: flex; flex-wrap: wrap; gap: .55rem; color: rgba(229,255,250,.58); font-size: .63rem; }.project-card__stats span { display: inline-flex; align-items: center; gap: .2rem; }.project-card__stats .q-icon { color: #50dcc4; }.project-card__actions { display: flex; align-items: center; gap: .15rem; }.portal-module__dialog { width: min(94vw, 680px); color: #effffb; background: #061819; border: 1px solid rgba(19,188,157,.3); }.portal-module__dialog-head { display: flex; align-items: flex-start; justify-content: space-between; gap: .8rem; }.portal-module__dialog h3 { margin: .4rem 0 0; font-size: 1.15rem; }.project-manager__link-head { display: flex; align-items: center; justify-content: space-between; margin-top: 1rem; color: #8fffee; font-size: .72rem; }.project-manager__link-row { display: grid; grid-template-columns: .8fr 1.2fr auto; gap: .45rem; margin-top: .45rem; }.project-manager__empty { display: grid; justify-items: start; gap: .3rem; padding: 2rem; color: rgba(239,255,251,.68); border: 1px dashed rgba(19,188,157,.25); border-radius: .7rem; }.project-manager__empty strong { color: #effffb; }.project-manager__empty .q-icon { color: #8fffee; }@media (max-width: 700px) { .portal-module__head { align-items: flex-start; flex-direction: column; }.portal-module__primary { width: 100%; }.project-manager__filters { width: 100%; }.project-manager__filters :deep(.q-field) { flex: 1; }.project-card { grid-template-columns: 56px 1fr; }.project-card__logo { width: 56px; height: 56px; }.project-card__footer { display: grid; justify-items: start; }.project-card__actions { width: 100%; justify-content: space-between; }.project-manager__link-row { grid-template-columns: 1fr; }.project-manager__link-row .q-btn { justify-self: end; }}
</style>
